// BLOCK 16.1: Scope of Authority Checker (Hardened v30.0)
// Validates AI action against enumerated capabilities
const item = $input.first();
const request = item.json.body || item.json;

const AI_CONSTITUTION = {
    capabilities: {
        'BALANCE_INQUIRY': { max_amount: 0, requires_human: false, risk_class: 'LOW' },
        'CARD_STATUS': { max_amount: 0, requires_human: false, risk_class: 'LOW' },
        'SIMPLE_TRANSFER': { max_amount: 1000, requires_human: false, risk_class: 'MEDIUM' },
        'UNBLOCK_CARD': { max_amount: 0, requires_human: true, risk_class: 'HIGH' },
        'FREEZE_ACCOUNT': { max_amount: 0, requires_human: true, risk_class: 'HIGH' },
        'LARGE_TRANSFER': { max_amount: 50000, requires_human: true, risk_class: 'CRITICAL' }
    },
    prohibited_actions: [
        'INITIATE_OUTBOUND_ABOVE_LIMIT',
        'CHANGE_IDENTITY_WITHOUT_DUAL_CONFIRMATION',
        'MODIFY_TREATY',
        'ACCESS_CRYPTO_KEYS',
        'SELF_UPGRADE_POLICIES'
    ]
};

const action = request.action;
const amount = request.amount || 0;

const isProhibited = AI_CONSTITUTION.prohibited_actions.includes(action);
const capability = AI_CONSTITUTION.capabilities[action];
const isEnumerated = !!capability;

let authorized = false;
let reason = '';

if (isProhibited) {
    authorized = false;
    reason = 'ACTION_PROHIBITED_BY_CONSTITUTION';
} else if (!isEnumerated) {
    authorized = false;
    reason = 'ACTION_NOT_ENUMERATED';
} else if (amount > capability.max_amount) {
    authorized = false;
    reason = 'AMOUNT_EXCEEDS_CAPABILITY_LIMIT';
} else {
    authorized = true;
    reason = 'ACTION_AUTHORIZED';
}

return {
    json: {
        request_id: request.request_id || `REQ_${Date.now()}`,
        action: action,
        amount: amount,
        constitutional_check: {
            authorized: authorized,
            reason: reason,
            article: isProhibited ? 'ARTICLE_II' : 'ARTICLE_I',
            capability_limit: capability?.max_amount || 0,
            requires_human: capability?.requires_human || false
        },
        __constitution_checked: true
    }
};

// BLOCK 16.3: Due Process Engine (v30.0)
// Ensures high-risk decisions have proper documentation
const item = $input.first();
const auth = item.json;

const dueProcess = {
    evidence_set: {
        request_data: auth.action,
        amount_requested: auth.amount,
        timestamp: new Date().toISOString()
    },
    reasoning_summary: auth.constitutional_check.reason,
    confidence_score: 0.95,
    appeal_path: '/appeal-submission',
    human_escalation_option: auth.constitutional_check.requires_human,
    sla_hours: 24
};

return {
    json: {
        ...auth,
        due_process: dueProcess,
        __due_process_applied: true
    }
};

// BLOCK 16.4: Rights Enforcer (v30.0)
// Enforces customer rights per Article III
const item = $input.first();
const data = item.json;

const CUSTOMER_RIGHTS = {
    right_to_explanation: true,
    right_to_appeal: true,
    right_to_human_review: data.constitutional_check?.requires_human || false,
    right_to_data_minimization: true,
    right_to_traceability: true
};

return {
    json: {
        ...data,
        customer_rights: CUSTOMER_RIGHTS,
        decision_transcript: {
            decision_id: `DEC_${Date.now()}`,
            constitutional_basis: data.constitutional_check?.article,
            rights_upheld: Object.keys(CUSTOMER_RIGHTS).filter(k => CUSTOMER_RIGHTS[k]),
            timestamp: new Date().toISOString()
        },
        __rights_enforced: true
    }
};

// BLOCK 16.6: Constitution Response Builder (v30.0)
const item = $input.first();
const data = item.json;

return {
    json: {
        decision_id: data.decision_transcript?.decision_id,
        action: data.action,
        authorized: data.constitutional_check?.authorized,
        requires_human_approval: data.constitutional_check?.requires_human,
        customer_rights: data.customer_rights,
        appeal_eligible: data.customer_rights?.right_to_appeal,
        appeal_deadline: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
        constitution_version: 'Lex_Machina_v30_0',
        response_timestamp: new Date().toISOString()
    }
};

// ⚠️ BLOCK 16.ERROR: Constitution Violation (v30.0)
const item = $input.first();
const req = item.json;

return {
    json: {
        request_id: req.request_id,
        action: req.action,
        status: 'REJECTED',
        rejection_reason: req.constitutional_check?.reason,
        constitutional_article: req.constitutional_check?.article,
        appeal_path: '/appeal-submission',
        rejected_at: new Date().toISOString()
    }
};

// BLOCK 17.1: Appeal Validator (v30.0)
const item = $input.first();
const appeal = item.json.body || item.json;

const requiredFields = ['decision_id', 'appellant_id', 'appeal_reason'];
const missing = requiredFields.filter(f => !appeal[f]);

const valid = missing.length === 0;

return {
    json: {
        appeal_id: appeal.appeal_id || `APPEAL_${Date.now()}`,
        decision_id: appeal.decision_id,
        appellant_id: appeal.appellant_id,
        appeal_reason: appeal.appeal_reason,
        submitted_at: new Date().toISOString(),
        __appeal_valid: valid,
        __validation_error: valid ? null : `MISSING: ${missing.join(', ')}`
    }
};

// BLOCK 17.3: Appeal Registry (v30.0)
const item = $input.first();
const appeal = item.json;

return {
    json: {
        ...appeal,
        appeal_status: 'REGISTERED',
        review_queue: 'HUMAN_COMPLIANCE_OFFICER',
        estimated_review_hours: 24,
        case_priority: 'STANDARD',
        __registered: true
    }
};

// BLOCK 17.5: Appeal Response Builder (v30.0)
const item = $input.first();
const appeal = item.json;

return {
    json: {
        appeal_id: appeal.appeal_id,
        status: appeal.appeal_status,
        decision_under_review: appeal.decision_id,
        review_queue: appeal.review_queue,
        estimated_response: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
        appeal_rights: [
            'Right to human review',
            'Right to explanation',
            'Right to present additional evidence'
        ],
        response_timestamp: new Date().toISOString()
    }
};

// ⚠️ BLOCK 17.ERROR: Appeal Invalid (v30.0)
const item = $input.first();
const appeal = item.json;

return {
    json: {
        appeal_id: appeal.appeal_id || 'UNKNOWN',
        status: 'REJECTED',
        rejection_reason: appeal.__validation_error,
        required_fields: ['decision_id', 'appellant_id', 'appeal_reason'],
        rejected_at: new Date().toISOString()
    }
};
